INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (2, 2, "訓練はまだ\nここからですわ", 1, 2, 1000, "vo_minigame_1013_icon_2_002_001", "調子が上がって\nきたなっ", 3000, "vo_minigame_1013_icon_1_002_001");
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (2, 2, "クスクス、悪くない\n流れですわね", 2, 2, 5000, "vo_minigame_1013_icon_2_003_001", "ほらほら、\nまだいけるだろ？", 3000, "vo_minigame_1013_icon_1_003_001");
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (2, 3, "すばらしい\n記録ですわ", 3, 2, 10000, "vo_minigame_1013_icon_2_004_001", "へへっ、おまえら\nやるじゃねえか！", 3000, "vo_minigame_1013_icon_1_004_001");
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (3, 3, "乗りに乗って\nいますわね", 4, 2, 10000, "vo_minigame_1013_icon_2_005_001", "あたしたちはまだ\n止まらねえぜ！", 3000, "vo_minigame_1013_icon_1_005_001");
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (3, 3, "まだまだ行きます\nついてきなさい", 5, 2, 10000, "vo_minigame_1013_icon_2_005_002", "見てろよ！\nマコト班の快進撃だ！", 3000, "vo_minigame_1013_icon_1_005_002");
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (3, 3, "エリコ班の\n本領発揮ですわ！", 6, 2, 10000, "vo_minigame_1013_icon_2_005_003", "うおぉぉっ！\n絶好調だぜ！", 3000, "vo_minigame_1013_icon_1_005_003");
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (4, 3, "ここからは\n前人未到の領域です！", 7, 2, 0, "vo_minigame_1013_icon_2_006_001", "どこまで行けるか\n楽しみだなっ！", 3000, "vo_minigame_1013_icon_1_006_001");
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (5, 4, "厄介でしたわ…", 8, 3, 1, "vo_minigame_1013_icon_2_007_001", "まだ諦めんなよっ", 1000, "vo_minigame_1013_icon_1_007_001");
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (5, 4, "油断大敵です", 9, 3, 1, "vo_minigame_1013_icon_2_007_002", "冷やっとしたぜ…！", 1000, "vo_minigame_1013_icon_1_007_002");
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (5, 4, "忌々しいっ…", 10, 3, 1, "vo_minigame_1013_icon_2_007_003", "弱音を吐くなっ", 1000, "vo_minigame_1013_icon_1_007_003");
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (6, 3, "大所帯ですわね", 11, 4, 99, "vo_minigame_1013_icon_2_008_001", "マコト班集合！", 1500, "vo_minigame_1013_icon_1_008_001");
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (6, 3, "エリコ班へようこそ", 12, 4, 99, "vo_minigame_1013_icon_2_008_002", "連携してくぞ！", 1500, "vo_minigame_1013_icon_1_008_002");
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (8, 6, "ナナカちゃんに\nお任せあれ", 13, 1, 0, "vo_minigame_1013_icon_2_020_001", "みんなに力を！", 3000, "vo_minigame_1013_icon_1_020_001");
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (9, 7, "はっはっは！\n任せろ！", 14, 1, 0, "vo_minigame_1013_icon_2_022_001", "任せてくれたまえ", 3000, "vo_minigame_1013_icon_1_022_001");
INSERT INTO `v1_fc13ee7d456121e30d44f0357f969ac2bf55580bdf9c61d14f5a7bcb556d8002` VALUES (10, 8, "どんどんいくわよ", 15, 1, 0, "vo_minigame_1013_icon_2_023_001", "ほな、いきまひょか", 3000, "vo_minigame_1013_icon_1_023_001");
